-- Non-destructive Patient Management additions. Run once as HOSPITAL_APP.
CREATE SEQUENCE PATIENT_NUMBER_SEQ START WITH 1 INCREMENT BY 1 NOCYCLE CACHE 20;
CREATE TABLE ADMISSIONS (ADMISSION_ID NUMBER GENERATED BY DEFAULT AS IDENTITY, PATIENT_ID NUMBER NOT NULL, ADMISSION_DATE TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL, DISCHARGE_DATE TIMESTAMP, STATUS VARCHAR2(20) DEFAULT 'ADMITTED' NOT NULL, CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL, UPDATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL, CONSTRAINT PK_ADMISSIONS PRIMARY KEY(ADMISSION_ID), CONSTRAINT FK_ADMISSIONS_PATIENT FOREIGN KEY(PATIENT_ID) REFERENCES PATIENTS(PATIENT_ID), CONSTRAINT CK_ADMISSIONS_STATUS CHECK(STATUS IN('ADMITTED','DISCHARGED','CANCELLED')));
CREATE INDEX IDX_ADMISSIONS_PATIENT ON ADMISSIONS(PATIENT_ID);
